var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"예상은 했지만 조잡한 집이로군.","JPN":"予想はしていたが、粗末な家だな。","ENG":"It is not unexpected, but it is truly a crude house.","TWN":"雖然已經有心理準備，但這房子還真是簡陋。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"산 꼭대기 마을이라더니. 이런 열악한 환경에서 잘도 살아남았어.","JPN":"山の頂上にある村だと聞いたが。このような劣悪な環境でよくも生き延びたものだ。","ENG":"A village atop a mountain. It is a miracle they survived in such harsh conditions.","TWN":"雖說是山頂上的村莊，沒想到竟能在這樣惡劣的環境中生存下來。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"귀하신 분을 이런 누추한 곳에 모시니 송구스럽기 그지없습니다.","JPN":"高貴な方をこのようなむさ苦しいところでおもてなしすることとなり、大変心苦しい限りです。","ENG":"I wish there was somewhere less lacking for our royal guests to stay at. I apologize.","TWN":"實在是非常抱歉，只有這麼簡陋的地方可以招待貴客。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"전하께서 괜찮으시다면 축제를 앞당기는 것도 가능합니다만….","JPN":"殿下さえよろしければ、祭りの時期を早めることもできますが……","ENG":"With your permission, we could hold the festival a bit earlier...","TWN":"若殿下不介意，也要把慶典提前也不是不可以…"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"됐다. 백성을 보호해야 할 황족이 어찌 그들에게 도움을 받을 수 있겠나.","JPN":"いや、いい。民を保護すべき皇族が、逆に助けられるわけにはいかない。","ENG":"Leave it. Royalty is supposed to protect their subjects, not receive assistance from them.","TWN":"沒關係，身為應該保護百姓的皇族，怎能接受他們的幫助呢。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"맞습니다. 평소 호의호식을 누리는 전하께서 설마 이 정도 곤욕도 못 치루시겠습니까.","JPN":"そのとおりです。普段贅沢に暮らしている殿下が、まさかこの程度の困難も耐えられないはずがありません。","ENG":"I agree. His Highness is in clover every other day, so he can stand to put up with a bit of trouble for a couple days.","TWN":"說得對，殿下平時吃好穿好的，這對殿下而言小意思吧？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당장 궁정에서 나오는 대궁만으로도 이곳 주민들이 배불리 먹을 수 있을 텐데요.","JPN":"今日宮廷から出る残飯だけでも、ここの住民が存分に食べられるはずです。","ENG":"Not to mention that the leftover food from the palace would be more than enough to feed this entire village.","TWN":"光是宮裡的剩菜剩飯就能夠餵飽這裡所有的居民吧。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이전부터 느낀 것이지만 성녀는 말이 많으시군요.","JPN":"前から思っていたのですが、聖女はおしゃべりですね。","ENG":"I am repeatedly reminded of how verbose you are, Saintess.","TWN":"我從以前就覺得，聖女真是多話。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"긴 혀가 문제라면 제가 조금 도려내 드리겠습니다.","JPN":"長い舌のせいでしたら、少し切り取ってさしあげましょう。","ENG":"If it is your tongue length that's bothering you, I'll gladly trim it.","TWN":"如果長舌頭是個問題，我可以幫你割掉一些。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…알았으니까 칼 좀 집어넣으시죠.","JPN":"……わかりましたから、剣をおさめてください。","ENG":"...Okay, so you can put your sword away.","TWN":"……不用客氣，請收起你的刀。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"둘 다 진정해. 모처럼 촌장님이 권유해 주셨는데 민폐를 끼칠 순 없잖아.","JPN":"二人とも落ち着いて。せっかく村長が誘ってくれたのに、ご迷惑をかけるわけにはいかないでしょう？","ENG":"Calm down, both of you. We can't be a nuisance, not when the chief invited us to stay.","TWN":"二位都冷靜點，難得村長邀請我們，怎麼能給人家添麻煩呢。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"촌장님. 축제에 대해 조금 더 자세히 설명해주실 수 있나요?","JPN":"村長。お祭りについて、もうちょっと詳しく説明してくれませんか？","ENG":"Chief, could you tell us more about this festival?","TWN":"村長，可以再多說一點關於這個慶典的事嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"이런. 이 늙은이가 깜빡하고 설명도 안 해드렸나 봅니다.","JPN":"おやおや。わしとしたことが、うっかり説明もしていなかったようですな。","ENG":"Oh dear. I must've forgotten to explain further.","TWN":"真是糟糕，看看我這個老糊塗，竟然忘記跟各位介紹一下。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"혹시 구원자님께서는 제국 무도회의 기원이 무엇인지 알고 계십니까?","JPN":"救世主様は帝国の舞踏会の起源についてご存じでしょうか？","ENG":"Do you happen to know how the Imperial Ball first started, Savior?","TWN":"救贖者大人大人，您知道帝國舞會的起源嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아뇨. 전 시골에서 살아서 무도회는 이번이 처음이거든요.","JPN":"いいえ。僕は田舎育ちなので、舞踏会はこれが初めてです。","ENG":"No. I lived in the countryside, I've never been to a ball before.","TWN":"不太清楚，因為我之前都住在鄉下，這是我第一次參加舞會。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"무도회가 있다는 것도 실은 얼마 전에 처음 알았어요.","JPN":"舞踏会があるってことも、実はこの前初めて知ったんです。","ENG":"I only recently found out that this ball existed.","TWN":"其實有舞會的事我也是前陣子才知道的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"제국이 생기기 이전, 사람들은 풍작을 위해 풍요의 신께 제사를 올렸다고 전해지지요.","JPN":"帝国の建国前、人々は豊作のために豊穣の神への祭祀を行っていたと伝えられております。","ENG":"It is said that, before the Empire came to be, people used to pray to the god of prosperity for a bountiful harvest.","TWN":"在帝國創立之前，人們會向豐饒之神祭祀祈求豐收。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"몬테는 전통을 이어받아 지금까지도 그 명맥을 이어 나가고 있습니다.","JPN":"モンテは伝統を受け継ぎ、今でもそれを守り続けています。","ENG":"Even after all this time, Monte has been keeping the tradition alive.","TWN":"蒙特延續這個傳統至今，"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"매년 순정한 남녀 한 쌍을 뽑아, 마을의 풍요를 기원하며 신께 제를 올리는 것이지요.","JPN":"毎年、無垢な男女を選抜し、村の豊穣を祈りながら祭祀を行うのです。","ENG":"We select a chaste couple to perform a rite, praying to the gods for the prosperity of the village.","TWN":"每年選出一對純真的男女，向神祈求村莊的豐收。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"풍작을 위한 제사인가. 제법 풍류가 있는 마을이로군.","JPN":"豊作のための祭祀か。なかなか趣のある村だ。","ENG":"A rite for a bountiful harvest. The village upholds more culture than I thought.","TWN":"原來目的是要祈求豐收，很棒的傳統呢。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그래서 말인데, 혹여 성녀님이 괜찮으시다면 이번 축제의 제를 부탁드릴 수 있겠습니까?","JPN":"それでなのですが、よろしければ聖女様に今度の祭りの祭祀を司っていただけないでしょうか？","ENG":"And while we are on the subject of the rite, could I ask you to perform it, Saintess?","TWN":"所以，若是聖女不介意，這次的祭祀能否由您來主持？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"제국의 성녀께서 직접 제를 올린다면 분명 신께서도 기뻐하실 겁니다.","JPN":"帝国の聖女様が直接祭祀を行うとなれば、きっと神もお喜びになられるでしょう。","ENG":"There is no doubt that god would be pleased if the Empire's Saintess performs the rite herself.","TWN":"帝國的聖女親自主持祭祀，神一定會很高興的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"별 상관은 없습니다만. 제라면 구체적으로 어떤 걸 하는 건가요?","JPN":"別に構いませんが。祭祀というと、具体的に何をするのですか？","ENG":"I do not think it would be impossible. But what would the rite entail?","TWN":"我是無所謂，只是具體而言祭祀要做什麼？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그리 어려운 일은 아닙니다.","JPN":"そう難しいことではありません。","ENG":"It's nothing too complicated.","TWN":"不難。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"대대로 내려오는 신의를 입고 상대 남성분과 춤을 춰 주시기만 하면…","JPN":"代々伝えられている神衣を着て、相手方の男性と踊ってくだされば……","ENG":"The rite is performed by a woman in sacred garments dancing with her partner–","TWN":"只需要穿上祖傳的聖衣，與另一位祭祀的男子共舞…"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"거절하겠습니다.","JPN":"お断りします。","ENG":"I will have to decline.","TWN":"我拒絕。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하! 당대의 성녀가 신에 대한 무례를 저질러서야 되겠나?","JPN":"ハハ！　当代の聖女が、神に対し無礼を働いてどうする？","ENG":"Ha ha! You would dare disrespect god, Saintess?","TWN":"哈哈！聖女怎能對神不敬？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저는 부활의 성녀지. 남들 앞에서 춤을 추는 광대가 아닙니다.","JPN":"私は復活の聖女であって、人前で踊るピエロではありません。","ENG":"I am the Saintess of Resurrection, not a jester who dances for others' entertainment.","TWN":"我是復活的聖女，不是在人前跳舞的小丑。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그건 유감이군. 그대를 위해 궁정 광대자리까지 알아봤는데 말이다.","JPN":"それは残念だな。そなたのために、宮廷ピエロの役はないか調べていたのだが。","ENG":"What a shame. I was looking into the position of court jester for you.","TWN":"真是可惜，我本來還有意替你安排在宮裡耍戲法呢。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"성녀님께 강요할 생각은 없습니다. 지금껏 그래왔듯 마을 여성을 선별하면 그만이니까요.","JPN":"聖女様に無理強いするつもりはありません。今までそうだったように、村の女性を選抜すればいいのですから。","ENG":"I have no intention to force it on you, Saintess. We can do what we've always done and select a woman from the village.","TWN":"我無意強迫聖女。那就一如既往，從村裡選出一對男女就好。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아니지. 촌장. 고양이가 미끼를 물지 않는다면 더 큰 미끼를 준비하면 그만일세.","JPN":"いいや。村長。ネコがエサに食いつかないのなら、もっと大きなエサを用意すればいいだけのことだ。","ENG":"Wait a moment, chief. I think you just need a better prize.","TWN":"不，村長。如果小貓不咬餌，那就準備更大的餌吧。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"의식을 위한 남성은 따로 준비되어 있나?","JPN":"儀式のための男役はすでに用意されているのか？","ENG":"Has the man for the rite already been selected?","TWN":"那另外一位祭祀的男性是否已經選定？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"아직입니다. 축제를 위한 남녀는 보통 한 번에 선별하지요.","JPN":"まだです。祭りのための男女は、通常同時に選抜いたしますので。","ENG":"Not yet. We normally select the man and the woman at the same time.","TWN":"尚未，通常是同時選出來的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다면 얘기가 빠르겠군.","JPN":"なら、話が早い。","ENG":"That makes this easier.","TWN":"那事情會簡單很多。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민! 이번 축제의 남성 역은 네가 맡도록.","JPN":"平民！　今度の祭りでの男役は貴様が担当しろ。","ENG":"Peasant! You are to take the role of the man for this rite.","TWN":"平民！這次祭祀的男性角色由你來扮演。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네? 저 말인가요?","JPN":"え？　僕がですか？","ENG":"Pardon? Me?","TWN":"什麼？我嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"잠깐. 그게 무슨 말씀입니까, 전하!","JPN":"ちょっと。それはどういうことですか、殿下！","ENG":"Wait, what are you trying to do, Your Highness?!","TWN":"等一下，殿下，這是什麼意思？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"문제라도 있나? 신에게 제사를 올리는 것은 순정한 남녀 한 쌍이었을 텐데?","JPN":"問題でもあるのか？　神への祭祀を行うのは無垢な男女だったはずだ。","ENG":"Do you have a problem with that? A chaste woman and man are supposed to perform the rite, are they not?","TWN":"有問題嗎？主持祭祀的人應是純真的男女一對吧？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"못 미덥긴 해도 신민들에게는 희망의 상징인 녀석이다.","JPN":"少々頼りはないが、やつは臣民にとって希望の象徴だ。","ENG":"The peasant may not be the most reliable, but he is still a symbol of hope to my subjects.","TWN":"雖然他並不出色，但對百姓而言他是希望的象徵。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"남자 역으로 이만한 적임자는 없겠지.","JPN":"男役にこれほどの適任者はいないだろう。","ENG":"I don't see anyone more fit for the role of the man.","TWN":"還有比他更適合的人選嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"허허. 구원자님께서 도와주신다면 이 늙은이도 환영입니다.","JPN":"ほっほ。救世主様が手伝ってくださるのなら、この老人も歓迎です。","ENG":"Ha ha. I would be delighted if the Savior were to participate.","TWN":"呵呵。救贖者大人大人若能幫忙，我這老頭當然是很歡迎。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"멋대로 정하지 마세요. 중요한 건 구원자님의 의견입니다.","JPN":"勝手に決めないでください。大事なのは救世主様のご意見です。","ENG":"Don't be so presumptuous. We haven't even heard what the Savior has to say about this.","TWN":"別自作主張，最重要的是救贖者大人大人的意見。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"괜찮아, 루크레시아. 마을 사람들의 도움이 될 수 있다면 난 상관없어.","JPN":"大丈夫、ルクレシア。村のお役に立てるなら、僕は構わないよ。","ENG":"It's okay, Lucrecia. That's fine with me if I can be of assistance to the villagers.","TWN":"沒關係，盧克雷西亞。只要能幫到村民我無所謂。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 구원자님. 구원자님은 마을을 구한 것으로 이미 소임을 다하셨어요.","JPN":"ですが、救世主様。救世主様は村を救ったことですでにその役目を果たしています。","ENG":"But Savior, you have already done your part by saving this village.","TWN":"但救贖者大人大人，您已經完成使命拯救村莊。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지속된 전쟁으로 심신 모두 지치셨을 텐데, 이럴 필요는…….","JPN":"長引く戦争で心身ともに疲労されているでしょうに、その必要は……","ENG":"You must be mentally and physically tired from the continued battles. This is...","TWN":"接二連三的戰爭，您應該也是身心俱疲，沒必要再…"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아직 제복이 어울리는지는 모르겠지만, 흑색 제복이 무엇을 뜻하는지를 모르진 않아.","JPN":"まだ見合っているかどうかわからないけど、黒い礼装が何を意味してるのかはわかってる。","ENG":"I don't know if I'm living up to its reputation, but I still know what this black uniform represents.","TWN":"雖然我不確定我是否有資格穿上制服，但我知道這套黑色制服的意義。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"검만 잘 휘두른다고 구원자가 아니라는 것도 말이야.","JPN":"剣を上手に振り回すだけが救世主じゃないってこともね。","ENG":"And I know that swordsmanship isn't the Savior's sole priority.","TWN":"僅僅會揮劍並不能成為救贖者大人。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"알겠습니다. 구원자님의 뜻이 정 그러시다면 어쩔 수 없겠죠.","JPN":"わかりました。救世主様がそう言われるのであれば仕方ありません。","ENG":"Understood. If that is what you wish, I guess there is no other choice.","TWN":"好的，那就照您的意思吧。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"춤은… 어색하지만, 저도 최선을 다해 돕겠습니다.","JPN":"ダンスは……慣れていませんが、私も全力でお手伝いいたします。","ENG":"I'm not very familiar with dancing, but... I will do my best to assist you.","TWN":"雖然…我不太會跳舞，我會盡力配合的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"불순한 마음으로 순정을 자처하는 꼴이 퍽이나 우습다만.","JPN":"不純な心で無垢を自称する様はなかなか面白いが。","ENG":"It certainly is amusing how you claim to be chaste while harboring such impure thoughts.","TWN":"明明有一顆黑心，卻裝得很純情的樣子，真是好笑。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"유감이군, 루크레시아. 네 알량한 바람을 이루기에는 조금 늦은 것 같구나.","JPN":"残念だったな、ルクレシア。貴様のつまらない願いを叶えるには少々遅かったようだ。","ENG":"However, Lucrecia, it seems you are too late to fulfill your trifling desires.","TWN":"真是可惜， 露可蕾西亞，你卑微的心願這麼晚才實現。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"네? 갑자기 그게 무슨 말씀……","JPN":"はい？　いきなりどういう……","ENG":"Pardon? What do you mean–","TWN":"什麼？殿下什麼意思……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하. 말씀하신 대로 입후보를 희망하는 자들의 명단을 모아왔습니다.","JPN":"殿下。ご命令のとおり、立候補を希望する者のリストを集めてきました。","ENG":"Your Highness. Here is the list of all the villagers who wished to be candidates.","TWN":"殿下，已經照殿下的吩咐，收集完有意願參與祭祀的候選名單。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자가 상대라는 이야기에 마을 여성 대부분이 자원하더군요.","JPN":"救世主が相手と知ると、村のほとんどの女性が志願しました。","ENG":"Most of the female villagers volunteered after hearing that their partner would be the Savior.","TWN":"聽說對方救贖者大人大人，幾乎村裡所有的女生都搶著報名呢。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"정말 구원자님이야? 어떡해. 실물을 보는 건 처음이야!","JPN":"本当に救世主様なの？　どうしよう。実物は初めて！","ENG":"Is it really the Savior? Oh my, I've never seen him in person!","TWN":"真的是救贖者大人大人嗎？天哪，第一次見到本人欸！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자 님! 이쪽 좀 봐주세요!","JPN":"救世主様！　こっち向いて！","ENG":"Savior! Please, look this way!","TWN":"救贖者大人大人！請看這邊！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"자, 잠시만요. 여러분!","JPN":"ま、待ってください。皆さん！","ENG":"W-wait a second, everyone!","TWN":"各位先等一下！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하. 이게 대체 무슨 짓이십니까?","JPN":"殿下。これはいったいどういうことでしょうか。","ENG":"What is the meaning of this, Your Highness?","TWN":"殿下，這究竟是怎麼回事？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아무리 황족이라 한들 대대로 내려 온 전통을 무시할 수는 없으니 말이다.","JPN":"いくら皇族とは言え、代々受け継がれてきた伝統を無視するわけにはいかないからな。","ENG":"I may be the crown prince, but I would still like to respect the tradition of this village.","TWN":"雖然貴為皇族，但也不能藐視傳統。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"여성 쪽은 몬테의 전통대로 공정한 절차를 거쳐 선별할 예정이다.","JPN":"女の方はモンテの伝統どおり、公正な手続きで選抜する予定だ。","ENG":"Which is why we will select the woman for the rite through the procedure customary to Monte.","TWN":"女生的部分，會按蒙特的傳統公平競爭。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"왜 그러지? 무언가 하고 싶은 말이라도 있나?","JPN":"どうした？　何か言いたいことでもあるのか？","ENG":"What is it? Do you have anything you wish to say?","TWN":"怎麼？你有什麼想說嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하께서는 심보가 참 좋으시군요.","JPN":"殿下は本当によい性格をされておいでですね。","ENG":"How thoughtful of you, Your Highness.","TWN":"殿下真是心思縝密。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"덕분에 떠들썩한 축제가 될 것 같습니다.","JPN":"おかげさまで、賑やかなお祭りになりそうです。","ENG":"Thanks to you, this will become a lively festival.","TWN":"多虧有殿下，這將會是一個熱鬧的慶典。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하! 성녀께서 어련히 무도회에 참가하고 싶어했으니 말이다.","JPN":"ハハ！　聖女は舞踏会に参加したくて仕方がなかったからな。","ENG":"Ha ha! Your enthusiasm for the ball did not go unnoticed, Saintess.","TWN":"哈哈！意思是聖女很期待參加舞會吧。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부디 그대에게 즐거운 축제가 되었으면 좋겠군.","JPN":"そなたにとって楽しい祭りとなることを祈ろう。","ENG":"I certainly hope you enjoy this festival.","TWN":"希望你會享受這個日子。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};